{"type":"vega","params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json
  data: {
    url: {
      index: zeek-*
      body: {
        aggs: {
          lat_lon: {
            geotile_grid: {
              field: "geoip_dest.location"
              precision: 3
            }
            aggs: {
              centroid: { geo_centroid: { field: "geoip_dest.location" } }
            }
          }
        }
        size: 0
      }
    }
    format: { property: "aggregations.lat_lon.buckets" }
  }
  transform: [
    { calculate: "datum.centroid.location.lat", as: "lat" }
    { calculate: "datum.centroid.location.lon", as: "lon" }
    { calculate: "datum.doc_count", as: "count" }
  ]
  projection: { type: "naturalEarth1" }
  layer: [
    {
      mark: { type: "geoshape", fill: "#1a1a2e", stroke: "#00f5ff", strokeWidth: 0.3 }
      data: { url: "https://vega.github.io/editor/data/world-110m.json", format: { type: "topojson", feature: "countries" } }
    }
    {
      mark: { type: "circle", opacity: 0.8 }
      encoding: {
        longitude: { field: "lon", type: "quantitative" }
        latitude:  { field: "lat", type: "quantitative" }
        size:  { field: "count", type: "quantitative", scale: { range: [10, 800] } }
        color: { field: "count", type: "quantitative", scale: { scheme: "orangered" } }
        tooltip: [{ field: "count", title: "Alert Count" }]
      }
    }
  ]
  config: { background: "#0d1117", view: { stroke: null } }
}"},"aggs":[]}
